using UnityEngine;

public class CameraBlocker : MonoBehaviour
{
    [Header("Trigger (where it activates)")]
    [SerializeField] private BoxCollider2D triggerZone;

    [Header("Allowed bounds (what camera is allowed to show while inside)")]
    [SerializeField] private BoxCollider2D allowedBounds;

    private void Reset()
    {
        triggerZone = GetComponent<BoxCollider2D>();
    }

    private void Awake()
    {
        if (triggerZone == null) triggerZone = GetComponent<BoxCollider2D>();
        if (triggerZone != null) triggerZone.isTrigger = true;
    }

    private void OnTriggerEnter2D(Collider2D other)
    {
        if (!other.CompareTag("Player")) return;
        if (CameraManager.Instance != null)
            CameraManager.Instance.AddBlocker(allowedBounds);
    }

    private void OnTriggerExit2D(Collider2D other)
    {
        if (!other.CompareTag("Player")) return;
        if (CameraManager.Instance != null)
            CameraManager.Instance.RemoveBlocker(allowedBounds);
    }

#if UNITY_EDITOR
    private void OnDrawGizmosSelected()
    {
        if (allowedBounds == null) return;
        Gizmos.color = new Color(1f, 0.2f, 0.2f, 0.25f);
        Gizmos.DrawCube(allowedBounds.bounds.center, allowedBounds.bounds.size);
        Gizmos.color = new Color(1f, 0.2f, 0.2f, 0.9f);
        Gizmos.DrawWireCube(allowedBounds.bounds.center, allowedBounds.bounds.size);
    }
#endif
}
